exercises.solution_code:
#include <cassert>
#include <iostream>
#include <limits>

int safe_divide(int a, int b)
{
    assert(b != 0);
    return a / b;
}

int main()
{
    int n{};
    std::cin >> n;

    for (int i = 0; i < n; ++i)
    {
        int a{};
        int b{};

        if (!(std::cin >> a >> b))
        {
            std::cin.clear();
            std::cin.ignore(std::numeric_limits<std::streamsize>::max(), '\n');
            std::cout << "Error: invalid input\n";
            continue;
        }

        if (b == 0)
        {
            std::cout << "Error: division by zero\n";
            continue;
        }

        std::cout << "Result: " << safe_divide(a, b) << '\n';
    }

    return 0;
}

