exercises.solution_code:
#include <cassert>
#include <iostream>
#include <limits>

constexpr int TABLE_SIZE = 10;
constexpr int squares[TABLE_SIZE] = {0, 1, 4, 9, 16, 25, 36, 49, 64, 81};

static_assert(TABLE_SIZE > 0, "table must have positive size");
static_assert(squares[0] == 0, "first square must be 0");
static_assert(squares[9] == 81, "last square must be 81");

int lookupSquare(int index)
{
    assert(index >= 0 && index < TABLE_SIZE && "index out of bounds");
    return squares[index];
}

int main()
{
    int q{};
    std::cin >> q;

    for (int i = 0; i < q; ++i)
    {
        int index{};

        if (!(std::cin >> index))
        {
            std::cin.clear();
            std::cin.ignore(std::numeric_limits<std::streamsize>::max(), '\n');
            std::cout << "Error: invalid input\n";
            continue;
        }

        if (index >= 0 && index < TABLE_SIZE)
        {
            std::cout << "square(" << index << ") = " << lookupSquare(index) << '\n';
        }
        else
        {
            std::cout << "Error: index " << index << " out of range\n";
        }
    }

    std::cout << "Lookups complete.\n";

    return 0;
}
